import{_ as o,o as l,c as d,ai as a}from"./chunks/framework.BIXs0jTs.js";const r="/assets/preface-cover.Balx8Fq4.png",g=JSON.parse('{"title":"附录 D：常见问题与排错指南","description":"","frontmatter":{"title":"附录 D：常见问题与排错指南"},"headers":[],"relativePath":"90-appendix/faq.md","filePath":"90-appendix/faq.md","lastUpdated":null}'),t={name:"90-appendix/faq.md"};function c(i,e,n,s,p,u){return l(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="附录-d-常见问题与排错指南" tabindex="-1">附录 D　常见问题与排错指南 <a class="header-anchor" href="#附录-d-常见问题与排错指南" aria-label="Permalink to &quot;附录 D　常见问题与排错指南&quot;">​</a></h1><p><img src="'+r+'" alt="附录：常见问题解答与排错指南"></p><h2 id="d-1-claude-code-使用-faq" tabindex="-1">D.1 Claude Code 使用 FAQ <a class="header-anchor" href="#d-1-claude-code-使用-faq" aria-label="Permalink to &quot;D.1 Claude Code 使用 FAQ&quot;">​</a></h2><p><strong>Q: Claude Code 的响应速度突然变慢了？</strong> A: 这通常是因为上下文（Context）太大了。Claude 会读取你最近打开的所有文件和终端输出。 <strong>解决方案</strong>：</p><ol><li>运行 <code>/reset</code> 或 <code>/clear</code> 命令清除上下文。</li><li>使用 <code>.claudeignore</code> 排除不必要的大文件（如 <code>package-lock.json</code> 或 <code>dist/</code>）。</li></ol><p><strong>Q: 如何中断 Claude 正在执行的长任务？</strong> A: 在终端按 <code>Ctrl+C</code>。这会立即停止当前的生成或工具执行。</p><p><strong>Q: Claude 修改了我的代码，但我不想接受，怎么办？</strong> A: 如果你在 Plan Mode 下，直接拒绝即可。如果已经执行了，Claude Code 通常会自动为你创建一个 Git 提交。你可以使用 <code>git reset --hard HEAD~1</code> 回滚。 <strong>建议</strong>：始终在一个干净的 Git 分支上运行 Claude。</p><p><strong>Q: 为什么 Claude 总是找不到我的文件？</strong> A: 请检查你的工作目录（CWD）。Claude 默认只能看到当前目录下的文件。如果文件在子目录中，请使用相对路径。另外，检查该文件是否被 <code>.gitignore</code> 或 <code>.claudeignore</code> 忽略了。</p><h2 id="d-2-skill-与-mcp-开发-faq" tabindex="-1">D.2 Skill 与 MCP 开发 FAQ <a class="header-anchor" href="#d-2-skill-与-mcp-开发-faq" aria-label="Permalink to &quot;D.2 Skill 与 MCP 开发 FAQ&quot;">​</a></h2><p><strong>Q: 我配置了 MCP Server，但 Claude 说“找不到工具”？</strong> A: 排查步骤：</p><ol><li>检查 <code>claude_config.json</code> 中的命令路径是否正确（建议使用绝对路径）。</li><li>检查 Server 是否正常启动。你可以尝试手动运行该命令，看是否有报错。</li><li>如果是 Python Server，确保虚拟环境已激活，或使用 <code>uvx</code> / <code>pipx</code> 运行。</li><li>重启 Claude Code（配置更改需要重启生效）。</li></ol><p><strong>Q: 本地开发的 MCP Server 如何调试？</strong> A: 使用 MCP Inspector。</p><ol><li>运行 <code>npx @modelcontextprotocol/inspector &lt;你的 server 命令&gt;</code>。</li><li>在浏览器中打开 Inspector 提供的 URL。</li><li>你可以在网页上模拟发送请求，查看 Server 的响应日志。</li></ol><p><strong>Q: 遇到 <code>Connection refused</code> 或 <code>EADDRINUSE</code> 错误？</strong> A: 这通常发生在基于 HTTP/SSE 的 Server 上。</p><ul><li>确保端口没有被占用。</li><li>确保防火墙允许该端口的本地连接。</li><li>如果是 Docker 运行的 Server，检查端口映射 <code>-p</code> 参数。</li></ul><p><strong>Q: Claude 执行 SQL 时总是超时？</strong> A: 默认情况下，MCP 工具的执行时间是有限制的。对于慢查询：</p><ol><li>优化 SQL 语句（添加索引）。</li><li>在 Server 代码中增加超时时间设置。</li><li>让 Claude 分页查询（<code>LIMIT 100</code>）。</li></ol>',17)])])}const _=o(t,[["render",c]]);export{g as __pageData,_ as default};
